--
-- Table structure for table `billings`
--

DROP TABLE IF EXISTS `billings`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `billings` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `account_id` bigint unsigned DEFAULT NULL,
  `billing_period` varchar(7) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `total_amount` decimal(12,2) DEFAULT NULL,
  `issued_at` timestamp NULL DEFAULT NULL,
  `due_date` date DEFAULT NULL,
  `paid_at` timestamp NULL DEFAULT NULL,
  `meter_id` bigint unsigned DEFAULT NULL COMMENT 'DEPRECATED - use account_id instead',
  `amount_due` decimal(10,2) NOT NULL,
  `status` enum('pending','paid','overdue','partially_paid','voided') COLLATE utf8mb4_unicode_ci DEFAULT 'pending',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `billings_account_period_unique` (`account_id`,`billing_period`),
  KEY `billings_meter_id_foreign` (`meter_id`),
  KEY `billings_status_due_idx` (`status`,`due_date`),
  KEY `billings_status_duedate_idx` (`status`,`due_date`),
  KEY `billings_account_period_idx` (`account_id`,`billing_period`),
  KEY `billings_issued_at_idx` (`issued_at`),
  KEY `billings_status_paid_idx` (`status`,`paid_at`),
  CONSTRAINT `billings_meter_id_foreign` FOREIGN KEY (`meter_id`) REFERENCES `meters` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=2756 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

