--
-- Table structure for table `meters`
--

DROP TABLE IF EXISTS `meters`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `meters` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `account_id` bigint unsigned DEFAULT NULL,
  `resident_id` bigint unsigned DEFAULT NULL COMMENT 'OPTIONAL - specific resident using this meter',
  `meter_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `meter_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `location` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'analog' COMMENT 'NEEDS MIGRATION: Change to water|sewer enum',
  `meter_type` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'individual' COMMENT 'individual|bulk - bulk meters can have sub-meters',
  `parent_meter_id` bigint unsigned DEFAULT NULL COMMENT 'References meters.id - parent meter for sub-meters',
  `allocation_percentage` decimal(5,2) DEFAULT NULL COMMENT '% of parent meter consumption allocated to this sub-meter (0-100)',
  `status` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT 'active' COMMENT 'active|inactive|replaced|faulty',
  `installed_at` timestamp NULL DEFAULT NULL COMMENT 'When meter was installed',
  `installation_date` date DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `meters_meter_number_unique` (`meter_number`),
  KEY `meters_resident_id_foreign` (`resident_id`),
  KEY `idx_meters_account_id` (`account_id`),
  KEY `meters_meter_type_index` (`meter_type`),
  KEY `meters_parent_meter_id_index` (`parent_meter_id`),
  KEY `meters_account_status_idx` (`account_id`,`status`),
  KEY `meters_parent_type_idx` (`parent_meter_id`,`meter_type`),
  KEY `meters_meter_number_idx` (`meter_number`),
  KEY `meters_parent_meter_idx` (`parent_meter_id`),
  KEY `meters_type_status_idx` (`meter_type`,`status`)
) ENGINE=InnoDB AUTO_INCREMENT=51 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

